INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (1000, 13, "様々なミニゲームをご用意してい\nますよ！\nどのミニゲームで遊びますか？", "2030-04-01 14:00:00", "2020-02-15 15:00:00", 1000001, 0, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (1000, 13, "楽しいミニゲームをご紹介！\nあなたはどのミニゲームで\n遊びますか？", "2030-04-01 14:00:00", "2020-02-15 15:00:00", 1000002, 0, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (1001, 13, "こちらは{0}ルピで\n販売中！\nぜひ購入して\n遊んでくださいね！", "2030-04-01 14:00:00", "2020-02-15 15:00:00", 1001001, 0, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (1002, 12, "動くハートに合わせてタップ！\nシズルさんとエリコさんの\nチョコレートケーキ作りを\nお手伝いしましょう！", "2030-04-01 14:00:00", "2020-02-15 15:00:00", 1002001, 0, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (1003, 11, "クウカさんを引っ張ってより遠く\nへ飛ばしてあげましょう！\n色々なハプニングでクウカさんに\nエクスタシーを届けましょう！", "2030-04-01 14:00:00", "2020-02-15 15:00:00", 1003001, 0, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (1004, 3, "左右をタップしてマジムンを倒し\nましょう！\n放て！\n琉球犬アラウンドシュート！", "2030-04-01 14:00:00", "2020-02-15 15:00:00", 1004001, 0, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (1005, 7, "パネルをタップしてドラゴンズ\nネストのみなさんと一緒に\nしりとり対決をしませんか？\nおしりに「ん」はご法度です。", "2030-04-01 14:00:00", "2020-02-15 15:00:00", 1005001, 0, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (1006, 2, "素早い動きのネズミに合わせ、\nタップで撃退！\nやる気のリンさんと一緒に\n大切なチーズを守りましょう！", "2030-04-01 14:00:00", "2020-05-31 12:00:00", 1006001, 0, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (1007, 4, "ミサトさんや部員のみなさんと\nバッティングの特訓ですよ！\nホームランを目指して、ボールを\nタイミングよく打ち返しましょう", "2030-04-01 14:00:00", "2020-08-15 15:00:00", 1007001, 0, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (1008, 6, "カルミナメダルを使って、\n応援グッズをゲットしましょう！\nメダルはルピを使って\n交換できますよ。\n", "2030-04-01 14:00:00", "2021-08-31 12:00:00", 1008001, 0, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (1009, 13, "食べたプリンはプリンノート\nで確認してみましょう！\nプリンの材料はルピを使って\n購入できますよ。", "2030-04-01 14:00:00", "2021-12-18 15:00:00", 1009001, 0, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (1010, 4, "チームでクイズに挑みましょう！\nソロで自分の実力を試すか、マル\nチで仲間と一緒に遊ぶか、好きな\nモードを選んでくださいね♪", "2030-04-01 14:00:00", "2022-02-15 15:00:00", 1010001, 0, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (1011, 6, "３つのラウンドを駆け抜け、\n総合１位を目指しましょう！\n参加者の皆さんの特徴や、\nＧＰの特徴にも注目です♪", "2030-04-01 14:00:00", "2022-07-18 15:00:00", 1011001, 0, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (1012, 6, "キャルさん、スズナさんと一緒に\nクイズでお勉強しましょう！\n放課後の教室で二人きりって…\nなんだかドキドキしますね♪", "2030-04-01 14:00:00", "2023-09-18 15:00:00", 1012001, 0, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (1013, 6, "魔物の討伐任務にいざ行軍！\nエリコさん、マコトさんの\n頼もしい背中は、\n新兵さんたちの憧れですね♪", "2030-04-01 14:00:00", "2024-04-18 15:00:00", 1013001, 0, 190801);
INSERT INTO `v1_e2ebb310c7f902cfa515d7910d3e1150f1b469fac2fd186ec39e67bb2b4c87d0` VALUES (1014, 6, "バンディ・シスターズのみなさん\nと戦車バトルに挑戦です！\nパーツやメンバーの組み合わせで\nマシンの特徴が変化しますよ♪", "2030-04-01 14:00:00", "2024-11-18 15:00:00", 1014001, 0, 190801);
